import{_ as e,c as o,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"進階: 高級特性與工作流 | oh-my-opencode","description":"掌握 oh-my-opencode 的高級特性。學習 AI 代理團隊、並行任務、Categories/Skills 系統、生命週期鉤子等核心功能，實現高效 AI 工作流編排。","frontmatter":{"title":"進階: 高級特性與工作流 | oh-my-opencode","sidebarTitle":"像團隊一樣工作","subtitle":"進階: 高級特性與工作流","description":"掌握 oh-my-opencode 的高級特性。學習 AI 代理團隊、並行任務、Categories/Skills 系統、生命週期鉤子等核心功能，實現高效 AI 工作流編排。","order":60},"headers":[],"relativePath":"zh-tw/code-yeongyu/oh-my-opencode/advanced/index.md","filePath":"zh-tw/code-yeongyu/oh-my-opencode/advanced/index.md"}'),r={name:"zh-tw/code-yeongyu/oh-my-opencode/advanced/index.md"};function t(l,a,n,h,d,p){return s(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="進階" tabindex="-1">進階 <a class="header-anchor" href="#進階" aria-label="Permalink to &quot;進階&quot;">​</a></h1><p>本章節深入講解 oh-my-opencode 的高級特性：專業 AI 代理團隊、並行後臺任務、Categories 和 Skills 系統、生命週期鉤子等。掌握這些功能後，你將能夠像管理真實團隊一樣編排 AI 工作流，實現更高效的開發體驗。</p><h2 id="本章內容" tabindex="-1">本章內容 <a class="header-anchor" href="#本章內容" aria-label="Permalink to &quot;本章內容&quot;">​</a></h2><div class="grid-cards"><h3 id="ai-代理團隊-10-位專家介紹" tabindex="-1"><a href="./ai-agents-overview/">AI 代理團隊：10 位專家介紹</a> <a class="header-anchor" href="#ai-代理團隊-10-位專家介紹" aria-label="Permalink to &quot;[AI 代理團隊：10 位專家介紹](./ai-agents-overview/)&quot;">​</a></h3><p>全面介紹 10 個內置代理的功能、使用場景和調用方式。學會根據任務類型選擇合適的代理，實現高效團隊協作、並行任務執行與深度代碼分析。</p><h3 id="prometheus-規劃-面試式需求收集" tabindex="-1"><a href="./prometheus-planning/">Prometheus 規劃：面試式需求收集</a> <a class="header-anchor" href="#prometheus-規劃-面試式需求收集" aria-label="Permalink to &quot;[Prometheus 規劃：面試式需求收集](./prometheus-planning/)&quot;">​</a></h3><p>通過面試模式明確需求並生成工作計劃。Prometheus 會持續提問直到需求清晰，並自動諮詢 Oracle、Metis、Momus 驗證計劃質量。</p><h3 id="後臺並行任務-像團隊一樣工作" tabindex="-1"><a href="./background-tasks/">後臺並行任務：像團隊一樣工作</a> <a class="header-anchor" href="#後臺並行任務-像團隊一樣工作" aria-label="Permalink to &quot;[後臺並行任務：像團隊一樣工作](./background-tasks/)&quot;">​</a></h3><p>深入講解後臺代理管理系統的使用方法。學會並發控制、任務輪詢和結果獲取，讓多個 AI 代理同時處理不同任務，大幅提升工作效率。</p><h3 id="lsp-與-ast-grep-代碼重構利器" tabindex="-1"><a href="./lsp-ast-tools/">LSP 與 AST-Grep：代碼重構利器</a> <a class="header-anchor" href="#lsp-與-ast-grep-代碼重構利器" aria-label="Permalink to &quot;[LSP 與 AST-Grep：代碼重構利器](./lsp-ast-tools/)&quot;">​</a></h3><p>介紹 LSP 工具和 AST-Grep 工具的使用方法。展示如何實現 IDE 級別的代碼分析和操作，包括符號導航、引用查找、結構化代碼搜索。</p><h3 id="categories-和-skills-動態代理組合" tabindex="-1"><a href="./categories-skills/">Categories 和 Skills：動態代理組合</a> <a class="header-anchor" href="#categories-和-skills-動態代理組合" aria-label="Permalink to &quot;[Categories 和 Skills：動態代理組合](./categories-skills/)&quot;">​</a></h3><p>學會使用 Categories 和 Skills 系統創建專業化的子代理。實現靈活的代理組合，根據任務需求動態分配模型、工具和技能。</p><h3 id="內置-skills-瀏覽器自動化與-git-專家" tabindex="-1"><a href="./builtin-skills/">內置 Skills：瀏覽器自動化與 Git 專家</a> <a class="header-anchor" href="#內置-skills-瀏覽器自動化與-git-專家" aria-label="Permalink to &quot;[內置 Skills：瀏覽器自動化與 Git 專家](./builtin-skills/)&quot;">​</a></h3><p>詳細介紹三個內置 Skills（playwright、frontend-ui-ux、git-master）的使用場景和最佳實踐。快速接入瀏覽器自動化、前端 UI 設計、Git 操作等專業能力。</p><h3 id="生命週期鉤子-自動化上下文與質量控制" tabindex="-1"><a href="./lifecycle-hooks/">生命週期鉤子：自動化上下文與質量控制</a> <a class="header-anchor" href="#生命週期鉤子-自動化上下文與質量控制" aria-label="Permalink to &quot;[生命週期鉤子：自動化上下文與質量控制](./lifecycle-hooks/)&quot;">​</a></h3><p>介紹 32 個生命週期鉤子的使用方法。理解如何自動化上下文注入、錯誤恢復和質量控制，構建完整的 AI 工作流自動化體系。</p><h3 id="斜杠命令-預設工作流" tabindex="-1"><a href="./slash-commands/">斜杠命令：預設工作流</a> <a class="header-anchor" href="#斜杠命令-預設工作流" aria-label="Permalink to &quot;[斜杠命令：預設工作流](./slash-commands/)&quot;">​</a></h3><p>介紹 6 個內置斜杠命令的使用方法。包括 /ralph-loop（快速修復循環）、/refactor（代碼重構）、/start-work（啟動項目執行）等常用工作流。</p><h3 id="配置深度定製-代理與權限管理" tabindex="-1"><a href="./advanced-configuration/">配置深度定製：代理與權限管理</a> <a class="header-anchor" href="#配置深度定製-代理與權限管理" aria-label="Permalink to &quot;[配置深度定製：代理與權限管理](./advanced-configuration/)&quot;">​</a></h3><p>教會用戶深度自定義代理配置、權限設置、模型覆蓋和提示詞修改。掌握完整配置能力，打造符合團隊規範的 AI 工作流。</p></div><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  第 1 步                  第 2 步                     第 3 步                          第 4 步                  │</span></span>
<span class="line"><span>│  了解 AI 代理團隊    →   掌握規劃與並行     →   學會動態代理組合     →   深度定製與自動化       │</span></span>
<span class="line"><span>│  (基礎概念)               (核心能力)                 (高級用法)                   (專家級)                   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>建議順序</strong>：</p><ol><li><strong>先學 AI 代理團隊</strong>：了解 10 個代理的職責和使用場景，這是理解整個系統的基石。</li><li><strong>再學規劃與並行任務</strong>：掌握 Prometheus 規劃和後臺任務系統，這是高效協作的核心。</li><li><strong>接著學動態代理組合</strong>：學習 Categories 和 Skills，實現靈活的代理專業化。</li><li><strong>最後學深度定製</strong>：掌握生命週期鉤子、斜杠命令和配置定製，打造完整工作流。</li></ol><p><strong>進階路線</strong>：</p><ul><li>如果你的目標是<strong>快速上手</strong>：重點學習「AI 代理團隊」和「斜杠命令」</li><li>如果你的目標是<strong>團隊協作</strong>：深入學習「Prometheus 規劃」和「後臺並行任務」</li><li>如果你的目標是<strong>工作流自動化</strong>：學習「生命週期鉤子」和「配置深度定製」</li></ul><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前請確認</p><p>本章內容假設你已完成以下學習：</p><ul><li>✅ <a href="./../start/installation/">快速安裝與配置</a>：已安裝 oh-my-opencode 並配置至少一個 Provider</li><li>✅ <a href="./../start/sisyphus-orchestrator/">初識 Sisyphus：主編排器</a>：了解基本代理調用和委託機制</li><li>✅ <a href="./../platforms/provider-setup/">Provider 配置：Claude、OpenAI、Gemini</a>：已配置至少一個 AI Provider</li></ul></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章後，建議繼續學習：</p><ul><li><strong><a href="./../faq/troubleshooting/">配置診斷與故障排除</a></strong>：遇到問題時快速定位和解決。</li><li><strong><a href="./../appendix/configuration-reference/">配置參考</a>：</strong> 查看完整的配置文件 schema，了解所有配置選項。</li><li><strong><a href="./../appendix/claude-code-compatibility/">Claude Code 兼容性</a>：</strong> 了解如何將現有 Claude Code 工作流遷移到 oh-my-opencode。</li></ul>`,15)])])}const g=e(r,[["render",t]]);export{u as __pageData,g as default};
